#!/bin/bash

# ============================================================
#   RzStore Theme + Landing Page — All In One Installer
#   Pterodactyl v1.12.x
#   Version: 3.1.0
# ============================================================

RED='\033[0;31m'; GREEN='\033[0;32m'; YELLOW='\033[1;33m'
CYAN='\033[0;36m'; PURPLE='\033[0;35m'; BOLD='\033[1m'; NC='\033[0m'

PANEL_DIR="/var/www/pterodactyl"
BACKUP_DIR="/var/www/pterodactyl-theme-backup"
THEME_DIR="$PANEL_DIR/public/themes/rzstore"
PUBLIC_DIR="$PANEL_DIR/public"
VERSION="3.1.0"

info()    { echo -e "${CYAN}[INFO]${NC}  $1"; }
success() { echo -e "${GREEN}[OK]${NC}    $1"; }
warn()    { echo -e "${YELLOW}[WARN]${NC}  $1"; }
error()   { echo -e "${RED}[ERROR]${NC} $1"; }
step()    { echo -e "\n${PURPLE}━━━ $1 ━━━${NC}"; }

print_banner() {
    clear
    echo -e "${PURPLE}"
    echo "  ██████╗ ███████╗███████╗████████╗ ██████╗ ██████╗ ███████╗"
    echo "  ██╔══██╗╚══███╔╝██╔════╝╚══██╔══╝██╔═══██╗██╔══██╗██╔════╝"
    echo "  ██████╔╝  ███╔╝ ███████╗   ██║   ██║   ██║██████╔╝█████╗  "
    echo "  ██╔══██╗ ███╔╝  ╚════██║   ██║   ██║   ██║██╔══██╗██╔══╝  "
    echo "  ██║  ██║███████╗███████║   ██║   ╚██████╔╝██║  ██║███████╗"
    echo "  ╚═╝  ╚═╝╚══════╝╚══════╝   ╚═╝    ╚═════╝ ╚═╝  ╚═╝╚══════╝"
    echo -e "${NC}"
    echo -e "${CYAN}  ╔══════════════════════════════════════════════════════╗${NC}"
    echo -e "${CYAN}  ║  ${BOLD}RzStore All-In-One Installer v$VERSION${NC}${CYAN}           ║${NC}"
    echo -e "${CYAN}  ║  Landing Page + Dark Theme + Sidebar (User Only)     ║${NC}"
    echo -e "${CYAN}  ║  Support: Pterodactyl v1.12.x                        ║${NC}"
    echo -e "${CYAN}  ╚══════════════════════════════════════════════════════╝${NC}"
    echo ""
}

check_root() {
    [[ $EUID -ne 0 ]] && error "Jalankan sebagai root!" && exit 1
}

check_panel() {
    [ ! -d "$PANEL_DIR" ] && error "Panel tidak ditemukan di $PANEL_DIR" && exit 1
    success "Panel ditemukan: $PANEL_DIR"
}

show_menu() {
    echo -e "${BOLD}Pilih aksi:${NC}"
    echo -e "  ${GREEN}[1]${NC} Install / Update RzStore Theme"
    echo -e "  ${YELLOW}[2]${NC} Uninstall — Kembali ke Tampilan Original"
    echo -e "  ${RED}[3]${NC} Keluar"
    echo ""
    read -rp "$(echo -e "${CYAN}Pilihan [1-3]: ${NC}")" CHOICE
}

do_backup() {
    step "Membuat Backup"
    local TS=$(date +"%Y%m%d_%H%M%S")
    local BP="$BACKUP_DIR/$TS"
    mkdir -p "$BP"
    for f in \
        "$PANEL_DIR/resources/views/templates/base/core.blade.php" \
        "$PANEL_DIR/resources/views/templates/wrapper.blade.php" \
        "$PANEL_DIR/resources/views/layouts/admin.blade.php" \
        "$PANEL_DIR/resources/views/layouts/scripts.blade.php"; do
        [ -f "$f" ] && cp "$f" "$BP/$(basename $f).bak" && success "Backup: $(basename $f)"
    done
    [ -d "$THEME_DIR" ] && cp -r "$THEME_DIR" "$BP/theme_old"
    [ -f "$PUBLIC_DIR/index.html" ] && cp "$PUBLIC_DIR/index.html" "$BP/index.html.bak"
    echo "$BP" > /tmp/rzstore_backup
    success "Backup: $BP"
}

