<script>
const canvas=document.getElementById('bg-canvas');
const ctx=canvas.getContext('2d');
canvas.width=window.innerWidth;canvas.height=window.innerHeight;
window.addEventListener('resize',()=>{canvas.width=window.innerWidth;canvas.height=window.innerHeight});
const CL=['#7c3aed','#06b6d4','#ec4899','#f59e0b'];
const pts=Array.from({length:60},()=>({x:Math.random()*canvas.width,y:Math.random()*canvas.height,vx:(Math.random()-.5)*.2,vy:(Math.random()-.5)*.2,r:Math.random()*1.5+.5,c:CL[Math.floor(Math.random()*4)],a:Math.random()*.3+.1}));
(function draw(){ctx.clearRect(0,0,canvas.width,canvas.height);pts.forEach(p=>{p.x+=p.vx;p.y+=p.vy;if(p.x<0)p.x=canvas.width;if(p.x>canvas.width)p.x=0;if(p.y<0)p.y=canvas.height;if(p.y>canvas.height)p.y=0;ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);ctx.fillStyle=p.c;ctx.globalAlpha=p.a;ctx.fill()});for(let i=0;i<pts.length;i++)for(let j=i+1;j<pts.length;j++){const dx=pts[i].x-pts[j].x,dy=pts[i].y-pts[j].y,d=Math.sqrt(dx*dx+dy*dy);if(d<110){ctx.beginPath();ctx.moveTo(pts[i].x,pts[i].y);ctx.lineTo(pts[j].x,pts[j].y);ctx.strokeStyle='#7c3aed';ctx.globalAlpha=(1-d/110)*.06;ctx.lineWidth=.5;ctx.stroke()}}ctx.globalAlpha=1;requestAnimationFrame(draw)})();
for(let i=0;i<8;i++){const o=document.createElement('div');o.className='float-orb';const s=Math.random()*3+2;const c=['rgba(124,58,237,.6)','rgba(6,182,212,.5)','rgba(236,72,153,.5)'];o.style.cssText=`width:${s}px;height:${s}px;background:${c[Math.floor(Math.random()*3)]};left:${Math.random()*100}%;animation-duration:${8+Math.random()*12}s;animation-delay:${Math.random()*8}s;`;document.body.appendChild(o)}
const obs=new IntersectionObserver(e=>{e.forEach(x=>{if(x.isIntersecting)x.target.classList.add('visible')})},{threshold:.1});
document.querySelectorAll('.reveal').forEach(el=>obs.observe(el));
function openOrder(n,p){document.getElementById('mpn').textContent=n;document.getElementById('mpp').textContent=p;document.getElementById('orderModal').classList.add('active')}
function closeOrder(){document.getElementById('orderModal').classList.remove('active')}
function selPay(el){document.querySelectorAll('.pay-opt').forEach(o=>o.classList.remove('selected'));el.classList.add('selected')}
function submitOrder(){
  const n=document.getElementById('f1').value,w=document.getElementById('f2').value;
  if(!n||!w){alert('Mohon isi nama dan nomor WhatsApp!');return}
  const plan=document.getElementById('mpn').textContent,price=document.getElementById('mpp').textContent;
  const pay=document.querySelector('.pay-opt.selected').textContent.trim();
  alert('✅ Order diterima!\n\nPaket: '+plan+'\nHarga: '+price+'\nPembayaran: '+pay+'\n\nAdmin akan menghubungi '+w+' segera!');
  closeOrder();
}
document.getElementById('orderModal').addEventListener('click',e=>{if(e.target===e.currentTarget)closeOrder()});
</script>
</body>
</html>
