generate_css() {
    cat > "$THEME_DIR/rzstore.css" << 'CSSEOF'
@import url('https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;500;600;700;800&family=Space+Grotesk:wght@400;500;600;700&display=swap');
:root{--rz-bg:#0a0a0f;--rz-bg3:#13131f;--rz-border:#1e1e35;--rz-accent:#8b5cf6;--rz-accent2:#06b6d4;--rz-pink:#ec4899;--rz-text:#f1f0ff;--rz-muted:#a09ec0;--rz-dim:#5a5880;--rz-success:#10b981;--rz-danger:#ef4444;--rz-radius:12px;--rz-radius-lg:16px;--rz-glow:0 0 30px rgba(139,92,246,.15);--rz-t:all .25s cubic-bezier(.4,0,.2,1);--rz-sbw:64px;--rz-sbw-open:240px}
*,*::before,*::after{box-sizing:border-box}
html,body{background:var(--rz-bg)!important;color:var(--rz-text)!important;font-family:'Outfit',sans-serif!important;-webkit-font-smoothing:antialiased}
::-webkit-scrollbar{width:5px;height:5px}::-webkit-scrollbar-track{background:transparent}::-webkit-scrollbar-thumb{background:linear-gradient(180deg,var(--rz-accent),var(--rz-accent2));border-radius:99px}
::selection{background:rgba(139,92,246,.3)}
body{padding-left:var(--rz-sbw)!important;transition:padding-left .3s ease!important}
body.rz-open{padding-left:var(--rz-sbw-open)!important}
body::before{content:'';position:fixed;top:0;left:var(--rz-sbw);right:0;height:2px;background:linear-gradient(90deg,var(--rz-accent),var(--rz-accent2),var(--rz-pink),var(--rz-accent));background-size:300% 100%;animation:rz-grad 4s linear infinite;z-index:9990;transition:left .3s ease}
body.rz-open::before{left:var(--rz-sbw-open)}
@keyframes rz-grad{0%{background-position:0% 0}100%{background-position:300% 0}}
#rz-sidebar{position:fixed;top:0;left:0;height:100vh;width:var(--rz-sbw);background:linear-gradient(180deg,#0d0d1c 0%,#08080f 100%);border-right:1px solid var(--rz-border);z-index:9999;display:flex;flex-direction:column;transition:width .3s cubic-bezier(.4,0,.2,1);overflow:hidden;box-shadow:4px 0 32px rgba(0,0,0,.6)}
#rz-sidebar.rz-open{width:var(--rz-sbw-open)}
#rz-logo{height:70px;display:flex;align-items:center;justify-content:center;padding:0 14px;border-bottom:1px solid var(--rz-border);cursor:pointer;flex-shrink:0;gap:0;background:linear-gradient(135deg,rgba(139,92,246,.07),rgba(6,182,212,.03));transition:var(--rz-t);overflow:hidden;position:relative}
#rz-sidebar.rz-open #rz-logo{gap:12px;justify-content:flex-start}
#rz-logo:hover{background:linear-gradient(135deg,rgba(139,92,246,.13),rgba(6,182,212,.07))}
.rz-logo-svg{width:36px;height:36px;flex-shrink:0;filter:drop-shadow(0 0 8px rgba(139,92,246,.6));animation:rz-pulse 3s ease-in-out infinite}
@keyframes rz-pulse{0%,100%{filter:drop-shadow(0 0 8px rgba(139,92,246,.6))}50%{filter:drop-shadow(0 0 18px rgba(6,182,212,.9))}}
.rz-logo-text{overflow:hidden;max-width:0;opacity:0;transition:max-width .3s ease,opacity .3s ease;white-space:nowrap}
#rz-sidebar.rz-open .rz-logo-text{max-width:160px;opacity:1}
.rz-logo-name{font-family:'Space Grotesk',sans-serif;font-size:17px;font-weight:700;background:linear-gradient(135deg,#8b5cf6,#06b6d4);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;line-height:1.1}
.rz-logo-sub{font-size:9px;color:var(--rz-dim);letter-spacing:.14em;text-transform:uppercase}
.rz-toggle{position:absolute;right:8px;top:50%;transform:translateY(-50%);width:20px;height:20px;display:flex;align-items:center;justify-content:center;opacity:0;transition:var(--rz-t);color:var(--rz-muted)}
#rz-logo:hover .rz-toggle{opacity:1}
.rz-toggle svg{width:14px;height:14px;fill:currentColor;transition:transform .3s ease}
#rz-sidebar.rz-open .rz-toggle svg{transform:rotate(180deg)}
#rz-nav{flex:1;overflow-y:auto;overflow-x:hidden;padding:8px 0;scrollbar-width:none}
#rz-nav::-webkit-scrollbar{display:none}
.rz-item{display:flex;align-items:center;width:100%;height:46px;padding:0 14px;gap:0;cursor:pointer;text-decoration:none!important;color:var(--rz-dim)!important;position:relative;transition:var(--rz-t);overflow:hidden}
#rz-sidebar.rz-open .rz-item{gap:14px}
.rz-item::before{content:'';position:absolute;left:0;top:20%;bottom:20%;width:3px;background:linear-gradient(180deg,var(--rz-accent),var(--rz-accent2));border-radius:0 3px 3px 0;opacity:0;transition:opacity .2s}
.rz-item:hover{background:rgba(139,92,246,.08)!important;color:var(--rz-text)!important}
.rz-item:hover::before{opacity:1}
.rz-item.rz-active{background:rgba(139,92,246,.14)!important;color:var(--rz-text)!important}
.rz-item.rz-active::before{opacity:1}
.rz-icon{width:36px;height:36px;display:flex;align-items:center;justify-content:center;flex-shrink:0;border-radius:10px;transition:var(--rz-t)}
.rz-item:hover .rz-icon,.rz-item.rz-active .rz-icon{background:rgba(139,92,246,.15)}
.rz-icon svg{width:17px;height:17px;fill:currentColor}
.rz-label{font-family:'Outfit',sans-serif;font-size:13.5px;font-weight:500;white-space:nowrap;overflow:hidden;max-width:0;opacity:0;transition:max-width .3s ease,opacity .3s ease}
#rz-sidebar.rz-open .rz-label{max-width:160px;opacity:1}
.rz-tip{position:fixed;left:calc(var(--rz-sbw) + 10px);background:#0f0f1a;color:var(--rz-text);font-family:'Outfit',sans-serif;font-size:12px;font-weight:500;padding:6px 12px;border-radius:8px;white-space:nowrap;pointer-events:none;border:1px solid var(--rz-border);z-index:99999;display:none;box-shadow:0 4px 24px rgba(0,0,0,.5)}
.rz-divider{height:1px;background:var(--rz-border);margin:6px 12px}
#rz-bottom{border-top:1px solid var(--rz-border);padding:8px 0;flex-shrink:0}
div[class*="bg-neutral-700"],div[class*="bg-neutral-800"],div[class*="bg-neutral-900"],div[class*="ContentBox"],.card,.box{background:var(--rz-bg3)!important;border:1px solid var(--rz-border)!important;border-radius:var(--rz-radius-lg)!important}
input,select,textarea{background:rgba(15,15,26,.9)!important;border:1px solid var(--rz-border)!important;border-radius:var(--rz-radius)!important;color:var(--rz-text)!important;font-family:'Outfit',sans-serif!important}
input:focus,select:focus,textarea:focus{border-color:var(--rz-accent)!important;box-shadow:0 0 0 3px rgba(139,92,246,.15)!important;outline:none!important}
input::placeholder{color:var(--rz-dim)!important}
h1,h2,h3,h4,h5,h6{font-family:'Outfit',sans-serif!important;color:var(--rz-text)!important}
a{color:var(--rz-accent)!important}a:hover{color:var(--rz-accent2)!important}
div[class*="ServerRow"]{background:var(--rz-bg3)!important;border:1px solid var(--rz-border)!important;border-radius:var(--rz-radius-lg)!important;transition:var(--rz-t)!important}
div[class*="ServerRow"]:hover{border-color:rgba(139,92,246,.3)!important;transform:translateY(-1px)!important;box-shadow:var(--rz-glow)!important}
CSSEOF
    success "rzstore.css dibuat!"
}

