function hideTopbar(){
  const check=()=>{
    document.querySelectorAll('body > div > nav, body > nav, #app nav').forEach(el=>{
      if(el.id==='rz-sidebar'||el.closest('#rz-sidebar')) return;
      try{
        const r=el.getBoundingClientRect();
        if(r.top<=2&&r.width>200) el.style.setProperty('display','none','important');
      }catch(e){}
    });
    document.querySelectorAll('body *').forEach(el=>{
      if(el.id==='rz-sidebar'||el.closest('#rz-sidebar')||el.id==='rz-tip') return;
      try{
        const s=window.getComputedStyle(el);
        const r=el.getBoundingClientRect();
        if((s.position==='fixed'||s.position==='sticky')&&r.top<=2&&r.width>window.innerWidth*.4&&r.height>28&&r.height<90){
          el.style.setProperty('display','none','important');
        }
      }catch(e){}
    });
  };
  check();
  const obs=new MutationObserver(check);
  obs.observe(document.body,{childList:true,subtree:true});
  setTimeout(()=>obs.disconnect(),10000);
}

function buildSidebar(){
  if(document.getElementById('rz-sidebar')) return;
  const isOpen=localStorage.getItem(OPEN_KEY)==='true';
  const path=window.location.pathname;
  const tip=document.createElement('div');
  tip.className='rz-tip';tip.id='rz-tip';document.body.appendChild(tip);
  const sb=document.createElement('div');
  sb.id='rz-sidebar';
  if(isOpen){sb.classList.add('rz-open');document.body.classList.add('rz-open');}
  sb.innerHTML=`<div id="rz-logo"><svg class="rz-logo-svg" viewBox="0 0 40 40" fill="none"><defs><linearGradient id="rzg1" x1="0" y1="0" x2="40" y2="40" gradientUnits="userSpaceOnUse"><stop offset="0%" stop-color="#8b5cf6"/><stop offset="100%" stop-color="#06b6d4"/></linearGradient><linearGradient id="rzg2" x1="0" y1="40" x2="40" y2="0" gradientUnits="userSpaceOnUse"><stop offset="0%" stop-color="#06b6d4"/><stop offset="100%" stop-color="#ec4899"/></linearGradient></defs><polygon points="20,1 39,20 20,39 1,20" fill="rgba(139,92,246,.1)" stroke="url(#rzg1)" stroke-width="1.5"/><polygon points="20,7 33,20 20,33 7,20" fill="rgba(139,92,246,.07)"/><text x="20" y="25" text-anchor="middle" font-family="Space Grotesk,sans-serif" font-size="12" font-weight="700" fill="url(#rzg2)" letter-spacing="-0.5">RZ</text><circle cx="20" cy="1" r="2" fill="url(#rzg1)"/><circle cx="39" cy="20" r="2" fill="url(#rzg1)"/><circle cx="20" cy="39" r="2" fill="url(#rzg1)"/><circle cx="1" cy="20" r="2" fill="url(#rzg1)"/></svg><div class="rz-logo-text"><div class="rz-logo-name">RzStore</div><div class="rz-logo-sub">Game Panel</div></div><div class="rz-toggle"><svg viewBox="0 0 24 24"><path d="M8.59 16.59L13.17 12 8.59 7.41 10 6l6 6-6 6z"/></svg></div></div><div id="rz-nav"></div><div id="rz-bottom"></div>`;
  document.body.prepend(sb);
  document.getElementById('rz-logo').addEventListener('click',toggle);
  const nav=document.getElementById('rz-nav');
  NAV.forEach(item=>{
    if(item.type==='divider'){nav.insertAdjacentHTML('beforeend','<div class="rz-divider"></div>');return;}
    const a=document.createElement('a');
    a.href=item.href;
    a.className='rz-item'+(item.match(path)?' rz-active':'');
    a.innerHTML=`<div class="rz-icon">${item.icon}</div><span class="rz-label">${item.label}</span>`;
    a.addEventListener('mouseenter',e=>showTip(e,item.label));
    a.addEventListener('mouseleave',hideTip);
    nav.appendChild(a);
  });
  const bottom=document.getElementById('rz-bottom');
  const out=document.createElement('a');
  out.href='/auth/logout';out.className='rz-item';
  out.style.cssText='color:rgba(239,68,68,.65)!important;';
  out.innerHTML=`<div class="rz-icon"><svg viewBox="0 0 24 24" fill="currentColor"><path d="M17 7l-1.41 1.41L18.17 11H8v2h10.17l-2.58 2.58L17 17l5-5zM4 5h8V3H4c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h8v-2H4V5z"/></svg></div><span class="rz-label">Logout</span>`;
  out.addEventListener('mouseenter',e=>showTip(e,'Logout'));
  out.addEventListener('mouseleave',hideTip);
  bottom.appendChild(out);
  initParticles();
}

function toggle(){const sb=document.getElementById('rz-sidebar');if(!sb)return;const open=sb.classList.toggle('rz-open');document.body.classList.toggle('rz-open',open);localStorage.setItem(OPEN_KEY,open)}
function showTip(e,text){const sb=document.getElementById('rz-sidebar');if(sb&&sb.classList.contains('rz-open'))return;const tip=document.getElementById('rz-tip');if(!tip)return;const r=e.currentTarget.getBoundingClientRect();tip.textContent=text;tip.style.top=(r.top+r.height/2-14)+'px';tip.style.display='block'}
function hideTip(){const t=document.getElementById('rz-tip');if(t)t.style.display='none'}

function initParticles(){
  const c=document.createElement('canvas');
  c.style.cssText='position:fixed;inset:0;pointer-events:none;z-index:-1;opacity:.18;';
  document.body.appendChild(c);
  const ctx=c.getContext('2d');
  let W=c.width=window.innerWidth,H=c.height=window.innerHeight;
  const CL=['#8b5cf6','#06b6d4','#ec4899'];
  const pts=Array.from({length:45},()=>({x:Math.random()*W,y:Math.random()*H,vx:(Math.random()-.5)*.25,vy:(Math.random()-.5)*.25,r:Math.random()*1.3+.4,c:CL[Math.floor(Math.random()*3)],a:Math.random()*.4+.15}));
  function draw(){ctx.clearRect(0,0,W,H);pts.forEach(p=>{p.x+=p.vx;p.y+=p.vy;if(p.x<0)p.x=W;if(p.x>W)p.x=0;if(p.y<0)p.y=H;if(p.y>H)p.y=0;ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);ctx.fillStyle=p.c;ctx.globalAlpha=p.a;ctx.fill()});for(let i=0;i<pts.length;i++)for(let j=i+1;j<pts.length;j++){const dx=pts[i].x-pts[j].x,dy=pts[i].y-pts[j].y,d=Math.sqrt(dx*dx+dy*dy);if(d<90){ctx.beginPath();ctx.moveTo(pts[i].x,pts[i].y);ctx.lineTo(pts[j].x,pts[j].y);ctx.strokeStyle='#8b5cf6';ctx.globalAlpha=(1-d/90)*.07;ctx.lineWidth=.4;ctx.stroke()}}ctx.globalAlpha=1;requestAnimationFrame(draw)}
  draw();window.addEventListener('resize',()=>{W=c.width=window.innerWidth;H=c.height=window.innerHeight});
}

function init(){buildSidebar();setTimeout(hideTopbar,500);setTimeout(hideTopbar,1500);setTimeout(hideTopbar,3000);console.log('%c✦ RzStore v3.1','color:#8b5cf6;font-size:14px;font-weight:700;')}
if(document.readyState==='loading') document.addEventListener('DOMContentLoaded',init);
else init();
})();
JSEOF
    success "rzstore.js dibuat!"
}

inject_blades() {
    step "Inject ke Blade Templates"
    local CSS='<!-- RZSTORE START --><link rel="preconnect" href="https://fonts.googleapis.com"><link rel="stylesheet" href="/themes/rzstore/rzstore.css?v=3.1.0"><!-- RZSTORE END -->'
    local JS='<!-- RZSTORE JS --><script defer src="/themes/rzstore/rzstore.js?v=3.1.0"></script><!-- /RZSTORE JS -->'
    for f in \
        "$PANEL_DIR/resources/views/templates/base/core.blade.php" \
        "$PANEL_DIR/resources/views/templates/wrapper.blade.php" \
        "$PANEL_DIR/resources/views/layouts/admin.blade.php" \
        "$PANEL_DIR/resources/views/layouts/scripts.blade.php"; do
        [ -f "$f" ] || continue
        # bersihkan injeksi lama
        sed -i '/<!-- RZSTORE/,/RZSTORE -->/d' "$f"
        sed -i '/<!-- LUXURY THEME/,/-->/d' "$f"
        sed -i '/sidebar\.\(css\|js\)\|luxury\.\(css\|js\)\|rzstore\.\(css\|js\)/d' "$f"
        # inject baru
        if grep -q "</head>" "$f"; then
            sed -i "s|</head>|$CSS\n</head>|" "$f"
        else
            echo -e "\n$CSS" >> "$f"
        fi
        if grep -q "</body>" "$f"; then
            sed -i "s|</body>|$JS\n</body>|" "$f"
        else
            echo -e "\n$JS" >> "$f"
        fi
        success "Injeksi: $(basename $f)"
    done
}

setup_nginx_landing() {
    step "Setup Route Landing Page"
    # Cek nginx config pterodactyl
    local NGINX_CONF=""
    for f in /etc/nginx/sites-enabled/pterodactyl.conf /etc/nginx/sites-enabled/default /etc/nginx/conf.d/pterodactyl.conf; do
        [ -f "$f" ] && NGINX_CONF="$f" && break
    done
    if [ -n "$NGINX_CONF" ]; then
        # Tambahkan route / ke landing page jika belum ada
        if ! grep -q "rzstore-landing" "$NGINX_CONF"; then
            sed -i "s|try_files \$uri \$uri/ /index.php?\$query_string;|try_files \$uri \$uri/ @rzlanding;\n        location = / { try_files /themes/rzstore/rzstore-landing.html =404; }\n        location @rzlanding { try_files \$uri /index.php?\$query_string; }|" "$NGINX_CONF" 2>/dev/null || true
        fi
        success "Nginx config diupdate!"
    else
        warn "Nginx config tidak ditemukan, landing page diakses manual di /themes/rzstore/rzstore-landing.html"
    fi
    # Copy landing ke public themes
    cp "$PUBLIC_DIR/rzstore-landing.html" "$THEME_DIR/rzstore-landing.html" 2>/dev/null || true
}

finish_install() {
    step "Permissions & Restart"
    chown -R www-data:www-data "$THEME_DIR" 2>/dev/null || chown -R nginx:nginx "$THEME_DIR" 2>/dev/null || true
    chmod -R 755 "$THEME_DIR"
    cd "$PANEL_DIR"
    php artisan view:clear 2>/dev/null && success "Cache cleared!"
    php artisan config:clear 2>/dev/null
    systemctl restart php8.3-fpm 2>/dev/null || systemctl restart php8.2-fpm 2>/dev/null || systemctl restart php8.1-fpm 2>/dev/null || true
    systemctl restart nginx 2>/dev/null && success "Nginx restarted!"
}

do_uninstall() {
    print_banner
    step "Uninstall — Kembali ke Tampilan Original"
    local LAST=""
    [ -f /tmp/rzstore_backup ] && LAST=$(cat /tmp/rzstore_backup)
    [ -z "$LAST" ] && LAST=$(ls -td "$BACKUP_DIR"/*/ 2>/dev/null | head -1)
    if [ -n "$LAST" ] && [ -d "$LAST" ]; then
        info "Backup: $LAST"
        read -rp "$(echo -e "${YELLOW}Restore backup? [y/N]: ${NC}")" C
        if [[ "$C" =~ ^[Yy]$ ]]; then
            for bak in "$LAST"/*.bak; do
                [ -f "$bak" ] || continue
                NAME=$(basename "$bak" .bak)
                ORIG=$(find "$PANEL_DIR/resources/views" -name "$NAME" 2>/dev/null | head -1)
                [ -n "$ORIG" ] && cp "$bak" "$ORIG" && success "Restored: $NAME"
            done
            [ -f "$LAST/index.html.bak" ] && cp "$LAST/index.html.bak" "$PUBLIC_DIR/index.html" && success "index.html restored"
        fi
    fi
    for f in \
        "$PANEL_DIR/resources/views/templates/base/core.blade.php" \
        "$PANEL_DIR/resources/views/templates/wrapper.blade.php" \
        "$PANEL_DIR/resources/views/layouts/admin.blade.php" \
        "$PANEL_DIR/resources/views/layouts/scripts.blade.php"; do
        [ -f "$f" ] || continue
        sed -i '/<!-- RZSTORE/,/RZSTORE -->/d' "$f"
        sed -i '/<!-- LUXURY THEME/,/-->/d' "$f"
        sed -i '/sidebar\.\(css\|js\)\|luxury\.\(css\|js\)\|rzstore\.\(css\|js\)/d' "$f"
        success "Cleaned: $(basename $f)"
    done
    [ -d "$THEME_DIR" ] && rm -rf "$THEME_DIR" && success "Folder tema dihapus!"
    [ -d "$PANEL_DIR/public/themes/luxury" ] && rm -rf "$PANEL_DIR/public/themes/luxury"
    [ -f "$PUBLIC_DIR/rzstore-landing.html" ] && rm -f "$PUBLIC_DIR/rzstore-landing.html"
    finish_install
    echo -e "\n${GREEN}╔══════════════════════════════════════════╗${NC}"
    echo -e "${GREEN}║  ✦  Panel kembali ke tampilan original!  ║${NC}"
    echo -e "${GREEN}╚══════════════════════════════════════════╝${NC}"
}

do_install() {
    print_banner
    step "Instalasi RzStore All-In-One v$VERSION"
    check_panel
    do_backup
    mkdir -p "$THEME_DIR" && success "Direktori: $THEME_DIR"
    step "Generate Landing Page"; generate_landing
    step "Generate CSS"; generate_css
    step "Generate JS"; generate_js
    inject_blades
    setup_nginx_landing
    finish_install
    echo ""
    echo -e "${PURPLE}╔════════════════════════════════════════════════════════╗${NC}"
    echo -e "${GREEN}║   ✦  RzStore All-In-One v$VERSION berhasil diinstall!   ║${NC}"
    echo -e "${PURPLE}║                                                        ║${NC}"
    echo -e "${PURPLE}║  🌐 Landing/Billing : rzstore.rians.biz.id             ║${NC}"
    echo -e "${PURPLE}║  🔐 User Panel      : rzstore.rians.biz.id/login       ║${NC}"
    echo -e "${PURPLE}║  ⚙️  Admin Panel     : rzstore.rians.biz.id/admin       ║${NC}"
    echo -e "${PURPLE}║                                                        ║${NC}"
    echo -e "${PURPLE}║  ▸ Sidebar RZ hanya muncul di user panel               ║${NC}"
    echo -e "${PURPLE}║  ▸ Admin panel tampilan original (tidak terganggu)     ║${NC}"
    echo -e "${PURPLE}║  ▸ Landing page billing tersedia                       ║${NC}"
    echo -e "${PURPLE}║                                                        ║${NC}"
    echo -e "${YELLOW}║  Tekan Ctrl+Shift+R di browser untuk refresh!          ║${NC}"
    echo -e "${PURPLE}╚════════════════════════════════════════════════════════╝${NC}"
}

check_root
print_banner
show_menu
case "$CHOICE" in
    1) do_install ;;
    2) do_uninstall ;;
    3) echo -e "\n${CYAN}Keluar!${NC}"; exit 0 ;;
    *) error "Pilihan tidak valid!"; exit 1 ;;
esac
